import { MSGraphClientV3 } from "@microsoft/sp-http";
import { getContext, ICurrentUser } from "./pnpService";
import { User } from "@hugeicons/core-free-icons";

// ─── Types ─────────────────────────────────────────────────────────────────────

export type EmailActionType =
  | "Released"
  | "Approved"
  | "Rework"
  | "ActualApproved"
  | "Export"
  | "Extension"
  | "TaxRegimeUpdate"
  | "Reopened";

export interface IEmailAttachment {
  name: string;
  contentBytes: string; // base64
  contentType: string;
}

export interface IEmailPayload {
  /** Action that triggered the email (Released, Approved, Rework). */
  action: EmailActionType;
  /** Declaration type: "Planned" or "Actual". */
  declarationType: "Planned" | "Actual";
  /** Full name of the employee. */
  employeeName: string;
  /** Employee ID / code. */
  employeeId: string;
  /** Financial year string, e.g. "2025-2026". */
  financialYear: string;
  /** Email address of the primary recipient. */
  toEmail: string | string[];
  /** Optional deadline date (used in Released emails). */
  deadline?: string;
  /** Optional approver comment (used in Rework emails). */
  approverComment?: string;
  reqno?: string;
  itemId?: string | number | null;
  user?: ICurrentUser;
  attachments?: IEmailAttachment[];
  newRegime?: string;
  ccEmail?: string | string[];
}
const _logoBase64: string = `data:image/jpeg;base64,`;
// ─── HTML Email Templates ───────────────────────────────────────────────────────
const mailHeader: string = `<div style="background-color: #3f51b5; padding: 12px; color: #ffffff; font-size: 20px;display:flex;justify-content:space-between;align-items:center;">
<label style="font-size:18px !important;font-weight:600">Roca Income Tax</label>
<img src="${_logoBase64}" width="200" height="60" > 
</div>`;

const buildEmailBody = (payload: IEmailPayload): string => {
  const {
    action,
    declarationType,
    financialYear,
    deadline,
    employeeName,
    user,
    itemId,
    reqno,
  } = payload;

  const context = getContext();
  const siteUrl = context.pageContext.web.absoluteUrl;
  let actionBody = "";
  let deepLink = "";
  if (action === "Released") {
    deepLink = `${siteUrl}/#/submittedDeclarations?tab=${declarationType}`;
  } else if (action === "ActualApproved") {
    deepLink = `${siteUrl}/#/declarationForm/${itemId}`;
  } else {
    deepLink = `${siteUrl}/#/submittedDeclarations?tab=${declarationType}`;
  }

  const detailsBlock = `<br /><br /><b>Declaration Details:</b><br /><br />Declaration Type: <b>${declarationType}</b><br /><br />Financial Year: <b>${financialYear}</b><br /><br />Request Number: <b>${reqno || "-"}</b>`;

  if (action === "Released") {
    actionBody = `<p>Dear ${employeeName},<br /><br />Income Tax Investment Workflow is active now for updating your investments.${detailsBlock}<br /><br />You have to update the investments on or before <b>${deadline ?? "the deadline"}</b>.<br /><br />Please note that once submitted you cannot alter.<br /><br />Please <a href="${deepLink}">click here</a> to access the portal.<br /><br />Thanks and regards,<br />${user?.Title || "ROCA IT Portal"}</p>`;
  } else if (action === "Approved") {
    const linkText =
      declarationType === "Actual"
        ? `<br /><br />Please <a href="${deepLink}">click here</a> to access your submitted declaration form.`
        : "";
    actionBody = `<p>Dear ${employeeName},<br /><br />Income tax declaration request has been approved.${detailsBlock}${linkText}<br /><br />Thanks and regards,<br />${user?.Title || "ROCA IT Portal"}</p>`;
  } else if (action === "Rework") {
    actionBody = `<p>Dear ${employeeName},<br /><br />Please check the remarks column in your income tax declaration and resubmit the data at the earliest.${detailsBlock}<br /><br />Thanks and regards,<br />${user?.Title || "ROCA IT Portal"}</p>`;
  } else if (action == "ActualApproved") {
    actionBody = `<p>Dear ${employeeName},<br /><br />Income tax declaration request has been approved.${detailsBlock}<br /><br /> Please <a href="${deepLink}">click here</a> to access your declaration form. <br /><br /> Thanks and regards,<br />${user?.Title || "ROCA IT Portal"}</p>`;
  } else if (action === "Export") {
    actionBody = `<p>Dear ${employeeName},<br /><br />Please find the attached Excel file for the <b>${financialYear}</b> Income Tax declarations.<br /><br />Thanks and regards,<br />ROCA IT Portal</p>`;
  } else if (action === "Extension") {
    actionBody = `<p>Dear ${employeeName},<br /><br />Your income tax declaration submission date has been extended to <b>${deadline ?? "the deadline"}</b>.${detailsBlock}<br /><br />Please <a href="${deepLink}">login</a> to the portal and complete your declaration.<br /><br />Thanks and regards,<br />${user?.Title || "ROCA IT Portal"}</p>`;
  } else if (action === "TaxRegimeUpdate") {
    actionBody = `<p>Dear ${employeeName},<br /><br />Your tax regime has been updated.${detailsBlock}<br /><br />Tax Regime type: <b>${payload.newRegime || "N/A"}</b><br /><br />Please <a href="${deepLink}">login</a> to the portal and complete your declaration if pending.<br /><br />Thanks and regards,<br />${user?.Title || "ROCA IT Portal"}</p>`;
  } else if (action === "Reopened") {
    actionBody = `<p>Dear ${employeeName},<br /><br />Your income tax declaration has been reopened for editing.${detailsBlock}<br /><br />Please <a href="${deepLink}">login</a> to the portal to update and resubmit your data.<br /><br />Thanks and regards,<br />${user?.Title || "ROCA IT Portal"}</p>`;
  }

  return `
      <div>
       <div>${mailHeader}</div>
        <div style="font-size:14px;color:#334155;">
          ${actionBody}
        </div>
        <div style="font-size:11px;color:#94a3b8;">
          This is an automated notification from the ROCA IT Declaration Portal.<br/>Please do not reply to this email.
        </div>
      </div>
  `;
};

// ─── Subject Lines ──────────────────────────────────────────────────────────────

const getSubject = (
  action: EmailActionType,
  declarationType: string,
  financialYear: string,
  reqno?: string,
  user?: ICurrentUser,
): string => {
  const subjects: Record<EmailActionType, string> = {
    Released: `INCOME TAX Investment Proofs for the FY ${financialYear} (${declarationType})`,
    Approved: `INCOME TAX Declaration Request (${declarationType}) :Req No ${reqno} - Approved`,
    Rework: `INCOME TAX Declaration Request (${declarationType}) for your rework :Req No ${reqno}`,
    ActualApproved: `INCOME TAX Declaration Request (${declarationType}) :Req No ${reqno} - Approved`,
    Export: `Declarations Exported - ${financialYear} (${declarationType})`,
    Extension: `INCOME TAX Declaration - Submission Date Extended (${declarationType})`,
    TaxRegimeUpdate: `INCOME TAX Declaration - Tax Regime Updated (${declarationType})`,
    Reopened: `INCOME TAX Declaration - Reopened (${declarationType})`,
  };
  return subjects[action];
};

// ─── Core Send Function ─────────────────────────────────────────────────────────

/**
 * Sends an IT Declaration notification email via Microsoft Graph API (`/me/sendMail`).
 *
 * Supported actions: "Released" | "Approved" | "Rework"
 *
 * @example
 * await sendDeclarationEmail({
 *   action: "Approved",
 *   declarationType: "Planned",
 *   employeeName: "Ravi Kumar",
 *   employeeId: "EMP001",
 *   financialYear: "2025-2026",
 *   toEmail: "ravi.kumar@company.com",
 * });
 */
export const sendDeclarationEmail = async (
  payload: IEmailPayload,
): Promise<void> => {
  try {
    const context = getContext();

    const graphClient: MSGraphClientV3 =
      await context.msGraphClientFactory.getClient("3");

    const emailMessage = {
      message: {
        subject: getSubject(
          payload.action,
          payload.declarationType,
          payload.financialYear,
          payload.reqno,
          payload.user,
        ),
        body: {
          contentType: "HTML",
          content: buildEmailBody(payload),
        },
        attachments: payload.attachments?.map((att) => ({
          "@odata.type": "#microsoft.graph.fileAttachment",
          name: att.name,
          contentType: att.contentType,
          contentBytes: att.contentBytes,
        })),
        toRecipients: (Array.isArray(payload.toEmail)
          ? payload.toEmail
          : payload.toEmail.split(",")
        )
          .filter((email) => !!email)
          .map((email) => ({
            emailAddress: {
              address: email.trim(),
            },
          })),
        ...(payload.ccEmail && {
          ccRecipients: (Array.isArray(payload.ccEmail)
            ? payload.ccEmail
            : payload.ccEmail.split(",")
          )
            .filter((email) => !!email)
            .map((email) => ({
              emailAddress: {
                address: email.trim(),
              },
            })),
        }),
      },
      saveToSentItems: false,
    };

    await graphClient.api("/me/sendMail").post(emailMessage);
  } catch (err) {
    console.error(
      `[emailService] Failed to send ${payload.action} email to ${payload.toEmail}:`,
      err,
    );
    // Non-blocking: swallow error so it does not break the main workflow
  }
};

/**
 * Convenience wrapper: send "Released" notifications to one or more employees.
 *
 * @param employees      Array of { email, name, id } objects — one email per employee.
 * @param declarationType  "Planned" | "Actual"
 * @param financialYear    e.g. "2025-2026"
 * @param deadline         Human-readable deadline string (optional)
 */
export const sendReleaseEmails = async (
  employees: { email: string; name: string; id: string; reqno?: string }[],
  declarationType: "Planned" | "Actual",
  financialYear: string,
  user: ICurrentUser,
  deadline?: string,
): Promise<void> => {
  const tasks = employees.map((emp) =>
    sendDeclarationEmail({
      action: "Released",
      declarationType,
      employeeName: emp.name,
      employeeId: emp.id,
      financialYear,
      toEmail: emp.email,
      deadline,
      user,
      reqno: emp.reqno,
    }),
  );
  await Promise.allSettled(tasks);
};

/**
 * Convenience wrapper: send an "Approved" notification to an employee.
 */
export const sendApprovalEmail = async (
  employeeName: string,
  employeeId: string,
  employeeEmail: string,
  declarationType: "Planned" | "Actual",
  financialYear: string,
  user: ICurrentUser,
  reqNo?: string,
  itemId?: string | number | null,
  action?: EmailActionType,
): Promise<void> => {
  await sendDeclarationEmail({
    action: action || "Approved",
    declarationType,
    employeeName,
    employeeId,
    financialYear,
    toEmail: employeeEmail,
    reqno: reqNo,
    itemId: itemId,
    user: user,
  });
};

/**
 * Convenience wrapper: send a "Rework" notification to an employee.
 */
export const sendReworkEmail = async (
  employeeName: string,
  employeeId: string,
  employeeEmail: string,
  declarationType: "Planned" | "Actual",
  financialYear: string,
  reqno: string,
  user: ICurrentUser,
  approverComment?: string,
): Promise<void> => {
  await sendDeclarationEmail({
    action: "Rework",
    declarationType,
    employeeName,
    employeeId,
    financialYear,
    toEmail: employeeEmail,
    approverComment,
    reqno: reqno,
    user: user,
  });
};

/**
 * Convenience wrapper: send an "Export" notification with attachment.
 */
export const sendExportEmail = async (
  toEmail: string,
  declarationType: "Planned" | "Actual",
  employeeName: string,
  fileName: string,
  base64Data: string,
  financialYear: string,
  ccEmails?: string[],
): Promise<void> => {
  await sendDeclarationEmail({
    action: "Export",
    declarationType: declarationType,
    employeeName,
    employeeId: "-", // Not needed for export
    financialYear,
    toEmail,
    ccEmail: ccEmails,
    attachments: [
      {
        name: fileName,
        contentBytes: base64Data,
        contentType:
          "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
      },
    ],
  });
};

